const item = $input.first();

// Se não for possível converter uma saída em objeto
if (!(item && Object.keys(item).length > 0)){
  console.log("Não foi possível converter uma saída em objeto.")
  return [{
    json: {
        message: "❌ Falha interna no processamento. Tente outra vez.",
        ok: false, 
        debug_completo: "Não foi possível converter uma saída em objeto." // Para debugar
    }
    }];
}

// 1. Transforma TUDO que chegou do nó anterior em texto plano. 
const erroCompleto = JSON.stringify(item);

/* Nota: o código abaixo foi desabilitado porque se a IA retornar erro por cota excedida, o fluxo fará a pesquisa de forma determinística na OpenWeather.

// 2. Procura pela mensagem de cota excedida dentro de todo o texto
if (erroCompleto.toLowerCase().includes("too many requests") || erroCompleto.includes("429")) {
    console.log("A cota de uso da Inteligência Artificial foi excedida.")
    return [{
        json: {
            message: "❌ Muitas requisições enviadas.\nContexto: A cota de uso da Inteligência Artificial foi excedida. O serviço retornará em breve.",
            ok: false
        }
    }];
}
*/

// 3. Tenta identificar uma mensagem de erro mais curta caso seja outro problema
let erroCurto = "Erro interno.";
if (item.error && typeof item.error.message === 'string') {
    erroCurto = item.error.message;
} else if (item.json && item.json.error && typeof item.json.error.message === 'string') {
    erroCurto = item.json.error.message;
} else if (item.json && typeof item.json.message === 'string') {
    erroCurto = item.json.message;
}

// 4. Se for outro erro, devolve o erro curto (e guarda o erro completo no debug)
console.log(erroCompleto)

return [{
    json: {
        message: "❌ Falha no processamento. Tente outra vez.\nContexto: " + erroCurto,
        ok: false, 
        debug_completo: erroCompleto // Para debugar
    }
}];

// Captura a resposta JSON que veio da OpenWeather
const data = $input.first().json;

// 1. Cenário de Erro: Cidade não encontrada (A API devolve cod: "404")

if (data.cod === "404" || data.cod === 404 || data.error?.status === 404 || data.error?.status === "404" ||
    data.cod === "400" || data.cod === 400 || data.error?.status === 400 || data.error?.status === "400" ) {
    return [{
        json: {
            message: "❌ Cidade não encontrada. Use o formato Cidade, UF (ex.: São Paulo, SP).",
            ok: false
        }
    }];
}

// 2. Cenário de Sucesso: A API retornou os dados climáticos
if (data.main && data.main.temp) {
  let nomeCidade = "";
  try {
    nomeCidade = $('consulta_cidade').first().json.name;
    } catch (error) {
        // Fallback: se errar o nome do nó, usa o que a API mandou mesmo
        nomeCidade = data.name; 
    }
    // Extrai a temperatura e arredonda para não mostrar casas decimais quebradas
    const temperatura = Math.round(data.main.temp);

    return [{
        json: {
            message: `🌤️ A temperatura em ${nomeCidade} é de ${temperatura}°C.`,
            ok: true
        }
    }];
}

// 3. Fallback Genérico: Caso a API caia ou mude a estrutura inesperadamente
return [{
    json: {
        message: "❌ Ocorreu um erro inesperado ao consultar o clima. Tente novamente mais tarde.",
        ok: false
    }
}];
